package com.finance.tracker.budget;
import com.finance.tracker.security.UserPrincipal; import jakarta.validation.Valid; import java.time.LocalDate; import java.util.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*; import org.springframework.http.HttpStatus;
@RestController @RequestMapping("/api/budgets") public class BudgetController {private final BudgetService service;public BudgetController(BudgetService service){this.service=service;}@GetMapping public List<BudgetService.BudgetResponse> list(@AuthenticationPrincipal UserPrincipal u,@RequestParam(required=false) Integer month,@RequestParam(required=false) Integer year){LocalDate now=LocalDate.now();return service.list(u.id(),month==null?now.getMonthValue():month,year==null?now.getYear():year);}@PostMapping @ResponseStatus(HttpStatus.CREATED) public BudgetService.BudgetResponse save(@AuthenticationPrincipal UserPrincipal u,@Valid @RequestBody BudgetService.BudgetRequest r){return service.save(u.id(),r);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@AuthenticationPrincipal UserPrincipal u,@PathVariable Long id){service.delete(u.id(),id);}}
